#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int A[105]; int B[105];
        for(int i=0;i<N;i++) scanf("%d", &A[i]);
        for(int i=0;i<N;i++) scanf("%d", &B[i]);
        int maxVal[105];
        for(int i=0;i<=N;i++) maxVal[i] = -101; // less than minimum possible B
        for(int i=0;i<N;i++){
            int type = A[i];
            if(B[i] > maxVal[type]) maxVal[type] = B[i];
        }
        long long ans = 0;
        for(int i=1;i<=N;i++) if(maxVal[i] > 0) ans += maxVal[i];
        printf("%lld\n", ans);
    }
    return 0;
}

