        for(int &x: B) cin>>x;
        vector<int> mx(N+1, -101);
        for(int i=0;i<N;i++){
            mx[A[i]] = max(mx[A[i]], B[i]);
        }
        long long ans=0;
        for(int i=1;i<=N;i++) if(mx[i]>0) ans+=mx[i];
        cout<<ans<<"\n";
    }
    return 0;
